<?php/DevelopmentErrorReportingif(!defined('DEVELOPMENT_MODE')){error_reporting(E_ALL);ini_set('display_errors',1);ini_set('display_startup_errors',1);}declare(strict_types=1);/***BaseControllerClass-PartofMVCArchitecture*Allcontrollersshouldextendthisclass*/abstractclassController{protected$db;protected$request;protected$response=[];publicfunction__construct(){$this->db=Database::getInstance();$this->request=$this->getRequestData();}/***Getrequestdata(GET/POST/JSON)*/protectedfunctiongetRequestData(){$method=$_SERVER['REQUEST_METHOD'];$data=[];switch($method){case'GET':$data=$_GET;break;case'POST':$contentType=$_SERVER['CONTENT_TYPE']??'';if(strpos($contentType,'application/json')!==false){$json=file_get_contents('php://input');$data=json_decode($json,true)??[];}else{$data=$_POST;}break;case'PUT':case'DELETE':$json=file_get_contents('php://input');$data=json_decode($json,true)??[];break;}return$this->sanitizeInput($data);}/***Sanitizeinputdata*/protectedfunctionsanitizeInput($data){if(is_array($data)){returnarray_map([$this,'sanitizeInput'],$data);}$data=trim($data);$data=stripslashes($data);$data=htmlspecialchars($data,ENT_QUOTES,'UTF-8');return$data;}/***SendJSONresponse*/protectedfunctionjson($data,$statusCode=200){http_response_code($statusCode);header('Content-Type:application/json;charset=UTF-8');echojson_encode($data,JSON_PRETTY_PRINT|JSON_UNESCAPED_UNICODE);exit;}/***Successresponse*/protectedfunctionsuccess($data=null,$message='Operationsuccessful'){$this->json(['success'=>true,'message'=>$message,'data'=>$data,'timestamp'=>date('c')]);}/***Errorresponse*/protectedfunctionerror($message='Anerroroccurred',$statusCode=400,$data=null){$this->json(['success'=>false,'message'=>$message,'data'=>$data,'timestamp'=>date('c')],$statusCode);}/***RedirecttoURL*/protectedfunctionredirect($url){header('Location:'.$url);exit;}/***Loadview*/protectedfunctionview($viewName,$data=[]){extract($data);$viewFile=__DIR__.'/../views/'.$viewName.'.php';if(file_exists($viewFile)){include$viewFile;}else{thrownewException("Viewnotfound:{$viewName}");}}/***CheckifrequestisAJAX*/protectedfunctionisAjax(){return!empty($_SERVER['HTTP_X_REQUESTED_WITH'])&&strtolower($_SERVER['HTTP_X_REQUESTED_WITH'])==='xmlhttprequest';}/***Validaterequiredfields*/protectedfunctionvalidateRequired($fields,$data=null){$data=$data??$this->request;$missing=[];forforeach($fieldsas$field){if(!isset($data[$field])||empty($data[$field])){$missing[]=$field;}}if(!empty($missing)){$this->error('Missingrequiredfields:'.implode(',',$missing),400,['missing_fields'=>$missing]);}returntrue;}/***Getspecificinputvalue*/protectedfunctioninput($key,$default=null){return$this->request[$key]??$default;}/***Setflashmessage*/protectedfunctionflash($message,$type='info'){if(session_status()===PHP_SESSION_NONE){session_start();}$_SESSION['flash_message']=['message'=>$message,'type'=>$type];}/***Getandclearflashmessage*/protectedfunctiongetFlash(){if(session_status()===PHP_SESSION_NONE){session_start();}if(isset($_SESSION['flash_message'])){$flash=$_SESSION['flash_message'];unset($_SESSION['flash_message']);return$flash;}returnnull;}}?>
